-- БЕЗОПАСНО: белый список таблиц + %I для идентификаторов
CREATE OR REPLACE FUNCTION get_data(tbl text)
RETURNS SETOF record SECURITY DEFINER AS $$
BEGIN
  IF tbl NOT IN ('sys_employee', 'sys_company') THEN
    RAISE EXCEPTION 'Invalid table: %', tbl;
  END IF;
  EXECUTE format('SELECT id, name FROM %I', tbl);
END;
$$ LANGUAGE plpgsql;

