example_good:
-- БЕЗОПАСНО: USING для параметров или прямой запрос
CREATE OR REPLACE FUNCTION search_emp(search_name text)
RETURNS SETOF sys_employee AS $$
BEGIN
  RETURN QUERY
  SELECT id, name, sur_name FROM sys_employee WHERE name = search_name;
  -- Или с динамическим SQL:
  -- EXECUTE 'SELECT id, name FROM sys_employee WHERE name = $1' USING search_name;
END;
$$ LANGUAGE plpgsql;

